    "file": "public 180;\r\n\r\nconst {\r\n    kOffset_OUTPUT_RootCA = 0;\r\n    kOffset_OUTPUT_Message  = kOffset_OUTPUT_RootCA + 32;\r\n    kOffset_OUTPUT_SESSION_Pubkey = kOffset_OUTPUT_Message + 32;\r\n    kOffset_OUTPUT_WORLD_Magic = kOffset_OUTPUT_SESSION_Pubkey + 32;\r\n    kOffset_OUTPUT_SESSION_Type = kOffset_OUTPUT_WORLD_Magic + 4;\r\n    kOffset_OUTPUT_Category = kOffset_OUTPUT_SESSION_Type + 4;\r\n    kOffset_OUTPUT_NotBefore = kOffset_OUTPUT_Category + 4;\r\n    kOffset_OUTPUT_NotAfter = kOffset_OUTPUT_NotBefore + 4;\r\n    kOffset_OUTPUT_Signature = kOffset_OUTPUT_NotAfter + 4;\r\n    kOffset_Output_mac = kOffset_OUTPUT_Signature + 64;\r\n    kSize_ENCRYPT_CHAIN = kOffset_Output_mac + 16;\r\n\r\n    kOffset_STORE_CIPHER = kOffset_Output_mac;\r\n    kSize_STORE_File = kOffset_STORE_CIPHER + 32;\r\n    kOffset_CIPHER = kSize_STORE_File;\r\n\r\n    kOffset_INPUT_ENCRYPT_CHAIN  = 256;\r\n    kOffset_INPUT_CV25519_Pubkey = 256 + kSize_ENCRYPT_CHAIN;\r\n    kOffset_SECRET_BYTES = 256;\r\n\r\n    i = 1024 - 4;\r\n    d = i - 4;\r\n    s = d - 4;\r\n    file = s - 4;\r\n}\r\n\r\n@ kOffset_OUTPUT_RootCA  [32] : rLANG_ROOT_Pubkey;\r\n@ kOffset_OUTPUT_Message [32] : rLANG_INPUT_Message;\r\n@ kOffset_OUTPUT_SESSION_Pubkey [32] : rLANG_SESSION_Pubkey;\r\n@ kOffset_OUTPUT_WORLD_Magic  i[4] : rLANG_WORLD_MAGIC;\r\n@ kOffset_OUTPUT_SESSION_Type i[4] : rLANG_INPUT_SESSION_Type;\r\n@ kOffset_OUTPUT_Category i[4] : rLANG_INPUT_Category;\r\n@ kOffset_OUTPUT_NotBefore i[4] : rLANG_INPUT_NotBefore;\r\n@ kOffset_OUTPUT_NotAfter i[4] : rLANG_INPUT_NotAfter;\r\n@ kOffset_OUTPUT_Signature [64] : rLANG_ROOT_Signature;\r\n\r\nrLANG_INPUT_ENCRYPT_CHAIN  @ kOffset_INPUT_ENCRYPT_CHAIN [kSize_ENCRYPT_CHAIN];\r\nrLANG_INPUT_CV25519_Pubkey @ kOffset_INPUT_CV25519_Pubkey[32];\r\n\r\n/**\r\n *!\r\n */\r\nMemcpy(0, kOffset_INPUT_ENCRYPT_CHAIN, 256);\r\n\r\n/**\r\n *! Master.X25519\r\n */\r\nMemset(kOffset_SECRET_BYTES, -1, 64);\r\nComputeSecretBytes(kOffset_SECRET_BYTES);\r\nExCurve25519ComputeSecret(kOffset_SECRET_BYTES + 32, kOffset_INPUT_CV25519_Pubkey, kOffset_CIPHER);\r\nDigestSM3(kOffset_SECRET_BYTES, 64, kOffset_SECRET_BYTES);\r\n\r\n/**\r\n *!\r\n */\r\nDigestSM3(kOffset_INPUT_CV25519_Pubkey, 32, kOffset_INPUT_CV25519_Pubkey); /// NONCE\r\nif(ExChaChaPolyOpen(kOffset_CIPHER, kOffset_INPUT_CV25519_Pubkey, 0,  kSize_ENCRYPT_CHAIN) != kOffset_STORE_CIPHER)\r\n    Exit(42);\r\nif(LoadU8(kOffset_OUTPUT_SESSION_Type) > 10)\r\n    Exit(14);\r\n\r\n/**\r\n *! 我们不验证解密后的数据是否是正确的, 错误的数据是无法通过客户验证的(TEXT长度实在是不够了)\r\n *! 1) **限制**: 现在的TEXT.SIZE太大了, 只能直接以Admin权限执行脚本了, 已经无法对TEXT做签名了, 不过我们应该没有在中途更换SESSION-KEY的需求 ...\r\n *! 2) **警告**: 正常的工作u-key不应该做SM2ECIES私钥托管, 在导入SESSION-KEY以后, 完成对SESSION_SIGNATURE脚本签名后就应该锁定u-key ...\r\n */\r\nMemcpy(kOffset_STORE_CIPHER, kOffset_CIPHER, 32);\r\n\r\nStoreI32(i, 0);\r\nStoreI32(d, kOffset_STORE_CIPHER);\r\nStoreI32(s, kOffset_SECRET_BYTES);\r\nwhile(LoadI32(i) < 32) {\r\n    StoreI32(d, LoadI32(d) ^ LoadI32(s));\r\n    StoreI32(i, LoadI32(i) + 4);\r\n    StoreI32(d, LoadI32(d) + 4);\r\n    StoreI32(s, LoadI32(s) + 4);\r\n}\r\n\r\nStoreI32(file, 0x100 + LoadU8(kOffset_OUTPUT_SESSION_Type));\r\nDeleteDataFile(LoadI32(file));\r\nCreateDataFile(LoadI32(file), kSize_STORE_File, 2, 2);\r\nWriteDataFile(LoadI32(file), 0, 0, kSize_STORE_File);\r\n\r\n/**\r\n *!\r\n */\r\nMemset(180, 0, 1024 - 180);\r\n"
